create or replace procedure p (
  v_rsv_no varchar2(10),
  v_rsv_seq number
)
IS
  v_max_rsv_seq number;
begin
  delete
  from 예약변경이력
  where 예약번호 = v_rsv_no
  and 예약변경회차 = v_rsv_seq;

  insert into 예약변경이력 (예약번호, 예약변경회차)
  values (v_rsv_no, v_rsv_seq);

  select max(예약변경회차)
  into v_max_rsv_seq
  from 예약변경이력
  where 예약번호 = v_rsv_no;

  merge into 예약현황 a
  using (select v_rsv_no 예약번호,
                v_max_rsv_seq 최종예약변경회차
         from dual
        ) b
  on (a.예약번호 = v_rsv_no)
  when not matched then
    insert (예약번호, 최종예약변경회차)
    values (v_rsv_no, v_max_rsv_seq);
  when matched then
    update set 최종예약변경회차 = v_max_rsv_seq;

  commit;
end;

